mapper.select:
SELECT ub.id, ub.user_id, ub.behavior_type AS behaviorType, ub.target_type AS targetType, ub.target_id AS targetId,
       ub.target_desc AS targetDesc, ub.ip, ub.device, ub.detail, ub.created_at AS createdAt,
       u.username, u.avatar_url AS userAvatar
FROM user_behaviors ub
LEFT JOIN users u ON ub.user_id = u.id

    AND ub.user_id = #{userId}

        AND u.username LIKE CONCAT('%', #{username}, '%')

    AND ub.behavior_type = #{behaviorType}

        AND (ub.target_desc LIKE CONCAT('%', #{keyword}, '%')
             OR ub.detail LIKE CONCAT('%', #{keyword}, '%'))


        AND ub.created_at >= #{startTime}


        AND ub.created_at <= #{endTime}


ORDER BY ub.created_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM user_behaviors ub
LEFT JOIN users u ON ub.user_id = u.id

    AND ub.user_id = #{userId}

        AND u.username LIKE CONCAT('%', #{username}, '%')

    AND ub.behavior_type = #{behaviorType}

        AND (ub.target_desc LIKE CONCAT('%', #{keyword}, '%')
             OR ub.detail LIKE CONCAT('%', #{keyword}, '%'))


        AND ub.created_at >= #{startTime}


        AND ub.created_at <= #{endTime}
